accessLogoutButton?.addEventListener("click", async () => {
  try {
    await fetch(apiPath("/api/access/logout"), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession({})),
    });
  } catch (_error) {
    // Logging out should always return the browser to the login gate.
  }
  accessAuthorized = false;
  setCurrentUser(null);
  window.location.reload();
});

writerModeInputs.forEach((input) => {
  input.addEventListener("change", async () => {
    const previousMode = getSiteWriterMode();
    if (!canCurrentUserUpdateWriterModeSettings()) {
      setWriterMode(previousMode);
      setMessage("LLM 사용 여부는 관리자만 변경할 수 있습니다.", true);
      return;
    }
    if (input.value === "mock" && input.checked) {
      llmAccessAuthorized = false;
      llmAccessToken = "";
      try {
        await saveSiteWriterMode("mock");
        setMessage("LLM 사용 설정을 미사용으로 저장했습니다. 모든 사용자에게 적용됩니다.");
        trackUserEvent("llm_mode_changed", { mode: "mock", scope: "site" });
      } catch (error) {
        setWriterMode(previousMode);
        setMessage(error.message || "LLM 사용 설정 저장에 실패했습니다.", true);
      }
      return;
    }
    if (input.value !== "llm" || !input.checked) return;
    try {
      const ok = await requestLlmAccess();
      if (!ok) {
        setWriterMode(previousMode);
        return;
      }
      await saveSiteWriterMode("llm", llmAccessToken);
      setMessage("LLM 사용 설정을 저장했습니다. 모든 사용자에게 적용됩니다.");
      trackUserEvent("llm_mode_changed", { mode: "llm", scope: "site" });
    } catch (error) {
      setWriterMode(previousMode);
      setMessage(error.message || "LLM 사용 설정 저장에 실패했습니다.", true);
    }
  });
});

function withClientSession(payload = {}) {
  const nextPayload = {
    ...payload,
    clientSessionId: CLIENT_SESSION_ID,
  };
  if (normalizeWriterModeValue(nextPayload.writerMode) === "llm" && getSiteWriterMode() === "llm") {
    nextPayload.useSiteWriterMode = true;
  }
  return nextPayload;
}

function trackUserEvent(eventName, details = {}) {
  if (!eventName) return;
  try {
    fetch(apiPath("/api/usage-events"), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession({ event: eventName, details })),
      keepalive: true,
    }).catch(() => {});
  } catch (_error) {
    // Usage logging must never block the main workflow.
  }
}

async function openAiConsultantModal() {
  if (!aiConsultantModal) return;
  aiConsultantModal.hidden = false;
  aiConsultantModal.removeAttribute("aria-hidden");
  hideAiConsultantFloatingLayers();
  renderAiConsultantNewSessionMenu();
  selectAiConsultant("ux", { silent: true });
  renderAiConsultantLlmState();
  renderAiConsultantConversation();
  renderAiConsultantAttachmentList();
  renderAiConsultantComposerState();
  setAiConsultantStatus("AI 컨설턴트 공용 세션을 불러오는 중입니다.");
  try {
    await loadAiConsultantSessions();
    if (aiConsultantActiveSessionId && aiConsultantSessions.some((session) => session.sessionId === aiConsultantActiveSessionId)) {
      await loadAiConsultantSession(aiConsultantActiveSessionId);
    } else {
      aiConsultantActiveSessionId = "";
      aiConsultantMessages = [];
      aiConsultantLatestResult = null;
      renderAiConsultantSessions();
      renderAiConsultantConversation();
      renderAiConsultantComposerState();
      setAiConsultantStatus("좌측에서 세션을 추가하거나 선택해 주세요.");
    }
  } catch (error) {
    setAiConsultantStatus(error.message || "AI 컨설턴트 세션을 불러오지 못했습니다.", true);
  }
  if (aiConsultantActiveSessionId) {
    window.setTimeout(() => aiConsultantInput?.focus(), 0);
  }
}

function closeAiConsultantModal() {
  if (!aiConsultantModal) return;
  stopAiConsultantThinkingTimer();
  stopAiConsultantPendingPoll();
  setAiConsultantBusy(false);
  setAiConsultantSessionActionBusy(false);
  closeAiConsultantDetailModal({ restoreFocus: false });
  hideAiConsultantFloatingLayers();
  setAiConsultantStatus("");
  aiConsultantModal.hidden = true;
  aiConsultantModal.setAttribute("aria-hidden", "true");
}

function isAiConsultantLlmReady() {
  return getSelectedWriterMode() === "llm";
}

function hasAiConsultantActiveSession() {
  return AI_CONSULTANT_VISIBLE_TYPES.includes(aiConsultantSelectedConsultant) && Boolean(aiConsultantActiveSessionId);
}

function renderAiConsultantComposerState() {
  const canUseComposer = hasAiConsultantActiveSession();
  if (aiConsultantComposer) {
    aiConsultantComposer.hidden = !canUseComposer;
  }
  if (!canUseComposer) {
    if (aiConsultantInput) aiConsultantInput.value = "";
    if (aiConsultantFileInput) aiConsultantFileInput.value = "";
    renderAiConsultantAttachmentList();
  }
  const disabled = !canUseComposer || aiConsultantInFlight || aiConsultantSessionActionInFlight || !AI_CONSULTANT_VISIBLE_TYPES.includes(aiConsultantSelectedConsultant);
  if (aiConsultantSendButton) aiConsultantSendButton.disabled = disabled;
  if (aiConsultantFileInput) aiConsultantFileInput.disabled = disabled;
  if (aiConsultantInput) aiConsultantInput.disabled = disabled;
}

function currentAiConsultantSession() {
  if (!aiConsultantActiveSessionId) return null;
  return aiConsultantSessions.find((session) => session.sessionId === aiConsultantActiveSessionId) || null;
}

function renderAiConsultantActiveSessionBar() {
  const session = currentAiConsultantSession();
  const hasActiveSession = Boolean(aiConsultantActiveSessionId && session);
  if (aiConsultantActiveSessionBar) {
    aiConsultantActiveSessionBar.hidden = !hasActiveSession;
  }
  if (!hasActiveSession) {
    if (aiConsultantToolbarDeleteButton) {
      aiConsultantToolbarDeleteButton.disabled = true;
    }
    return;
  }
  const consultant = normalizeAiConsultantType(session.consultant || aiConsultantSelectedConsultant);
  const badge = formatAiConsultantSessionBadge(consultant);
  const updated = formatAiConsultantSessionDate(session.lastUserMessageAt || session.updatedAt || session.lastMessageAt || session.createdAt);
  const created = formatAiConsultantSessionDate(session.createdAt);
  const ownerName = session.ownerName || "사용자";
  const lastActorName = publicAiConsultantBrandText(session.lastActorName || session.ownerName || "사용자");
  const title = publicAiConsultantBrandText(String(session.lastUserMessage || session.lastMessage || session.title || defaultAiConsultantSessionTitle(consultant)).trim());
  if (aiConsultantActiveSessionBadge) {
    aiConsultantActiveSessionBadge.className = `ai-consultant-session-badge ${consultant}`;
    aiConsultantActiveSessionBadge.textContent = badge;
  }
  if (aiConsultantActiveSessionTitle) {
    aiConsultantActiveSessionTitle.textContent = title || defaultAiConsultantSessionTitle(consultant);
  }
  if (aiConsultantActiveSessionMeta) {
    aiConsultantActiveSessionMeta.textContent = `생성 ${ownerName} / ${created} · 최종 ${lastActorName} / ${updated}`;
  }
  if (aiConsultantToolbarDeleteButton) {
    aiConsultantToolbarDeleteButton.disabled = aiConsultantSessionActionInFlight || !aiConsultantActiveSessionId;
  }
}

function normalizeAiConsultantType(value) {
  const normalized = String(value || "").trim().toLowerCase();
  return AI_CONSULTANT_TYPES.includes(normalized) ? normalized : "ux";
}

function isAiConsultantVisibleType(value) {
  const normalized = String(value || "").trim().toLowerCase();
  return AI_CONSULTANT_VISIBLE_TYPES.includes(normalized);
}

function normalizeVisibleAiConsultantType(value) {
  const normalized = String(value || "").trim().toLowerCase();
  return AI_CONSULTANT_VISIBLE_TYPES.includes(normalized) ? normalized : "ux";
}

function selectAiConsultant(consultant, { silent = false } = {}) {
  stopAiConsultantThinkingTimer();
  if (!aiConsultantInFlight) {
    stopAiConsultantPendingPoll();
  }
  aiConsultantSelectedConsultant = normalizeVisibleAiConsultantType(consultant);
  hideAiConsultantFloatingLayers();
  if (aiConsultantSessionHeading) {
    aiConsultantSessionHeading.textContent = "컨설팅 세션";
  }
  if (!silent) {
    setAiConsultantStatus(`${formatAiConsultantTypeLabel(aiConsultantSelectedConsultant)} 공용 세션을 불러오는 중입니다.`);
    loadAiConsultantSessions().catch((error) => {
      setAiConsultantStatus(error.message || `${formatAiConsultantTypeLabel(aiConsultantSelectedConsultant)} 세션을 불러오지 못했습니다.`, true);
    });
  }
}

function focusAiConsultantFloatingLayer(layer) {
  const focusable = focusableElementsIn(layer);
  if (focusable.length) {
    window.setTimeout(() => focusable[0].focus(), 0);
  }
}

function restoreAiConsultantFloatingFocus() {
  const focusTarget = aiConsultantLastFloatingTrigger;
  aiConsultantLastFloatingTrigger = null;
  if (
    focusTarget instanceof HTMLElement
    && focusTarget.isConnected
    && aiConsultantModal
    && !aiConsultantModal.hidden
  ) {
    window.setTimeout(() => focusTarget.focus(), 0);
  }
}

function showAiConsultantNewSessionMenu(triggerElement = aiConsultantNewSessionButton) {
  if (!aiConsultantNewSessionMenu) return;
  hideAiConsultantDeleteConfirm({ restoreFocus: false });
  aiConsultantLastFloatingTrigger = triggerElement instanceof HTMLElement ? triggerElement : aiConsultantNewSessionButton;
  aiConsultantNewSessionMenu.hidden = false;
  aiConsultantNewSessionButton?.setAttribute("aria-expanded", "true");
  focusAiConsultantFloatingLayer(aiConsultantNewSessionMenu);
}

function hideAiConsultantNewSessionMenu({ restoreFocus = false } = {}) {
  if (!aiConsultantNewSessionMenu) return;
  const wasOpen = !aiConsultantNewSessionMenu.hidden;
  aiConsultantNewSessionMenu.hidden = true;
  aiConsultantNewSessionButton?.setAttribute("aria-expanded", "false");
  if (restoreFocus && wasOpen) {
    restoreAiConsultantFloatingFocus();
  } else if (wasOpen && aiConsultantLastFloatingTrigger === aiConsultantNewSessionButton) {
    aiConsultantLastFloatingTrigger = null;
  }
}

function toggleAiConsultantNewSessionMenu(triggerElement = aiConsultantNewSessionButton) {
  if (!aiConsultantNewSessionMenu) return;
  if (aiConsultantNewSessionMenu.hidden) {
    showAiConsultantNewSessionMenu(triggerElement);
  } else {
    hideAiConsultantNewSessionMenu({ restoreFocus: true });
  }
}

function showAiConsultantDeleteConfirm(sessionId, triggerElement = null) {
  if (!aiConsultantDeleteConfirm || !sessionId) return;
  aiConsultantPendingDeleteSessionId = sessionId;
  hideAiConsultantNewSessionMenu({ restoreFocus: false });
  aiConsultantLastFloatingTrigger = triggerElement instanceof HTMLElement ? triggerElement : document.activeElement;
  aiConsultantDeleteConfirm.hidden = false;
  if (aiConsultantDeleteConfirmButton) aiConsultantDeleteConfirmButton.disabled = false;
  if (aiConsultantDeleteCancelButton) aiConsultantDeleteCancelButton.disabled = false;
  focusAiConsultantFloatingLayer(aiConsultantDeleteConfirm);
}

function hideAiConsultantDeleteConfirm({ restoreFocus = false } = {}) {
  const wasOpen = Boolean(aiConsultantDeleteConfirm && !aiConsultantDeleteConfirm.hidden);
  aiConsultantPendingDeleteSessionId = "";
  if (aiConsultantDeleteConfirm) {
    aiConsultantDeleteConfirm.hidden = true;
  }
  if (aiConsultantDeleteConfirmButton) aiConsultantDeleteConfirmButton.disabled = true;
  if (aiConsultantDeleteCancelButton) aiConsultantDeleteCancelButton.disabled = false;
  if (restoreFocus && wasOpen) {
    restoreAiConsultantFloatingFocus();
  } else if (wasOpen) {
    aiConsultantLastFloatingTrigger = null;
  }
}

function hideAiConsultantFloatingLayers({ restoreFocus = false } = {}) {
  const hadNewSessionMenu = Boolean(aiConsultantNewSessionMenu && !aiConsultantNewSessionMenu.hidden);
  const hadDeleteConfirm = Boolean(aiConsultantDeleteConfirm && !aiConsultantDeleteConfirm.hidden);
  const focusTarget = aiConsultantLastFloatingTrigger;
  hideAiConsultantNewSessionMenu({ restoreFocus: false });
  hideAiConsultantDeleteConfirm({ restoreFocus: false });
  if (restoreFocus && (hadNewSessionMenu || hadDeleteConfirm)) {
    aiConsultantLastFloatingTrigger = focusTarget;
    restoreAiConsultantFloatingFocus();
  } else if (hadNewSessionMenu || hadDeleteConfirm) {
    aiConsultantLastFloatingTrigger = null;
  }
  return hadNewSessionMenu || hadDeleteConfirm;
}

async function startAiConsultantSessionFor(consultant) {
  if (!isAiConsultantVisibleType(consultant)) {
    setAiConsultantStatus("현재 선택할 수 없는 컨설턴트입니다.", true);
    return;
  }
  const normalizedConsultant = normalizeVisibleAiConsultantType(consultant);
  selectAiConsultant(normalizedConsultant, { silent: true });
  hideAiConsultantNewSessionMenu({ restoreFocus: false });
  await createAiConsultantSession(defaultAiConsultantSessionTitle(normalizedConsultant));
}

function renderAiConsultantLlmState() {
  renderAiConsultantComposerState();
}

function setAiConsultantStatus(text, isError = false) {
  const messageText = String(text || "").trim();
  if (!aiConsultantToast) return;
  if (aiConsultantToastTimer) {
    window.clearTimeout(aiConsultantToastTimer);
    aiConsultantToastTimer = null;
  }
  if (!isError || !messageText) {
    aiConsultantToast.hidden = true;
    aiConsultantToast.textContent = "";
    aiConsultantToast.classList.remove("error", "success");
    return;
  }
  aiConsultantToast.textContent = messageText;
  aiConsultantToast.classList.toggle("error", true);
  aiConsultantToast.classList.remove("success");
  aiConsultantToast.hidden = false;
  aiConsultantToastTimer = window.setTimeout(() => {
    aiConsultantToast.hidden = true;
    aiConsultantToast.textContent = "";
    aiConsultantToast.classList.remove("error", "success");
    aiConsultantToastTimer = null;
  }, 5200);
}

function showAiConsultantToast(text, { isError = false } = {}) {
  const messageText = String(text || "").trim();
  if (!aiConsultantToast || !messageText) return;
  if (aiConsultantToastTimer) {
    window.clearTimeout(aiConsultantToastTimer);
    aiConsultantToastTimer = null;
  }
  aiConsultantToast.textContent = messageText;
  aiConsultantToast.classList.toggle("error", Boolean(isError));
  aiConsultantToast.classList.toggle("success", !isError);
  aiConsultantToast.hidden = false;
  aiConsultantToastTimer = window.setTimeout(() => {
    aiConsultantToast.hidden = true;
    aiConsultantToast.textContent = "";
    aiConsultantToast.classList.remove("error", "success");
    aiConsultantToastTimer = null;
  }, isError ? 5200 : 2400);
}

function setAiConsultantBusy(isBusy) {
  aiConsultantInFlight = Boolean(isBusy);
  if (aiConsultantSendButton) {
    const sendLabel = aiConsultantInFlight ? "상담 중" : "상담 보내기";
    aiConsultantSendButton.setAttribute("aria-label", sendLabel);
    aiConsultantSendButton.title = sendLabel;
    aiConsultantSendButton.innerHTML = `<span aria-hidden="true">↑</span>`;
  }
  renderAiConsultantLlmState();
  renderAiConsultantComposerState();
}

function setAiConsultantSessionActionBusy(isBusy) {
  aiConsultantSessionActionInFlight = Boolean(isBusy);
  if (aiConsultantNewSessionButton) aiConsultantNewSessionButton.disabled = aiConsultantSessionActionInFlight;
  aiConsultantNewSessionMenu?.querySelectorAll(".ai-consultant-option").forEach((button) => {
    button.disabled = aiConsultantSessionActionInFlight;
  });
  if (aiConsultantToolbarDeleteButton) aiConsultantToolbarDeleteButton.disabled = aiConsultantSessionActionInFlight || !aiConsultantActiveSessionId;
  if (aiConsultantDeleteConfirmButton) aiConsultantDeleteConfirmButton.disabled = aiConsultantSessionActionInFlight || !aiConsultantPendingDeleteSessionId;
  if (aiConsultantDeleteCancelButton) aiConsultantDeleteCancelButton.disabled = aiConsultantSessionActionInFlight;
  renderAiConsultantActiveSessionBar();
  renderAiConsultantComposerState();
}

function nextAiConsultantLocalMessageId(prefix = "local") {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

