function openAiConsultantDetailModal(messageKey, triggerElement = null) {
  const messageItem = findAiConsultantMessageByKey(messageKey);
  if (!messageItem?.result || !aiConsultantDetailModal || !aiConsultantDetailContent) return;
  aiConsultantLastDetailTrigger = triggerElement instanceof HTMLElement ? triggerElement : document.activeElement;
  const title = publicAiConsultantBrandText(messageItem.result.summary || "AI 컨설턴트 상세 보기");
  if (aiConsultantDetailTitle) {
    aiConsultantDetailTitle.textContent = title.length > 52 ? `${title.slice(0, 52)}...` : title;
  }
  aiConsultantDetailContent.innerHTML = renderAiConsultantDetailSections(messageItem.result);
  aiConsultantDetailModal.hidden = false;
  aiConsultantDetailModal.removeAttribute("aria-hidden");
  window.setTimeout(() => aiConsultantDetailCloseButton?.focus(), 0);
}

function closeAiConsultantDetailModal({ restoreFocus = true } = {}) {
  if (!aiConsultantDetailModal) return;
  aiConsultantDetailModal.hidden = true;
  aiConsultantDetailModal.setAttribute("aria-hidden", "true");
  if (aiConsultantDetailContent) aiConsultantDetailContent.innerHTML = "";
  const focusTarget = aiConsultantLastDetailTrigger;
  aiConsultantLastDetailTrigger = null;
  if (
    restoreFocus
    && focusTarget instanceof HTMLElement
    && focusTarget.isConnected
    && aiConsultantModal
    && !aiConsultantModal.hidden
  ) {
    window.setTimeout(() => focusTarget.focus(), 0);
  }
}

