function isAiConsultantImageFile(file) {
  const type = String(file?.type || "").toLowerCase();
  const name = String(file?.name || "").toLowerCase();
  return type.startsWith("image/") || /\.(png|jpe?g|webp)$/.test(name);
}

function formatAiConsultantFileSize(size) {
  const kb = Math.max(1, Math.ceil(Number(size || 0) / 1024));
  if (kb < 1024) return `${kb}KB`;
  return `${(kb / 1024).toFixed(1)}MB`;
}

function formatAiConsultantEvidenceType(value) {
  const normalized = String(value || "").trim().toLowerCase();
  const labels = {
    principle: "원칙",
    case_study: "Case Study",
    research_finding: "Research",
    pattern: "Pattern",
    anti_pattern: "Anti-pattern",
    bcg_framework: "B사 프레임워크",
    bcg_method: "B사 방법론",
    bcg_industry_method: "B사 산업 방법론",
    mckinsey_framework: "M사 프레임워크",
    mckinsey_method: "M사 방법론",
    mckinsey_industry_method: "M사 산업 방법론",
    consulting_method: "컨설팅 방법론",
    project: "Project",
  };
  return labels[normalized] || value || "근거";
}

async function readAiConsultantAttachments() {
  const files = [...(aiConsultantFileInput?.files || [])].slice(0, 5);
  const attachments = [];
  for (const file of files) {
    if (isAiConsultantImageFile(file)) {
      if (file.size > 2 * 1024 * 1024) {
        throw new Error(`${file.name} 이미지는 2MB 이하만 첨부할 수 있습니다.`);
      }
      const image = await readAiConsultantImageMeta(file);
      attachments.push({
        name: file.name,
        type: file.type || "",
        kind: "image",
        size: file.size,
        image,
      });
      continue;
    }
    if (file.size > 512 * 1024) {
      throw new Error(`${file.name} 파일은 512KB 이하만 첨부할 수 있습니다.`);
    }
    let text = "";
    try {
      text = await file.text();
    } catch (_error) {
      text = "";
    }
    attachments.push({
      name: file.name,
      type: file.type || "",
      kind: "text",
      size: file.size,
      text: String(text || "").slice(0, 60000),
    });
  }
  return attachments;
}

function readAiConsultantImageMeta(file) {
  return new Promise((resolve) => {
    if (typeof Image === "undefined" || typeof URL === "undefined" || !URL.createObjectURL) {
      resolve({ width: 0, height: 0, orientation: "unknown", aspectRatio: "", reviewMode: "metadata_only" });
      return;
    }
    const url = URL.createObjectURL(file);
    const img = new Image();
    let settled = false;
    const timeoutId = window.setTimeout(() => {
      done({ width: 0, height: 0, orientation: "unknown", aspectRatio: "", reviewMode: "metadata_only" });
    }, 1500);
    const done = (meta) => {
      if (settled) return;
      settled = true;
      window.clearTimeout(timeoutId);
      URL.revokeObjectURL(url);
      resolve(meta);
    };
    img.onload = () => {
      const width = Number(img.naturalWidth || img.width || 0);
      const height = Number(img.naturalHeight || img.height || 0);
      const orientation = width && height
        ? (width > height ? "landscape" : (height > width ? "portrait" : "square"))
        : "unknown";
      done({
        width,
        height,
        orientation,
        aspectRatio: width && height ? `${(width / height).toFixed(2)}:1` : "",
        reviewMode: "metadata_only",
      });
    };
    img.onerror = () => {
      done({ width: 0, height: 0, orientation: "unknown", aspectRatio: "", reviewMode: "metadata_only" });
    };
    img.src = url;
  });
}

