function appendAiConsultantLocalMessage(role, content, { result = null, attachments = [], pendingType = "", elapsedSeconds = 0, consultant = "", job = null } = {}) {
  const message = {
    localId: nextAiConsultantLocalMessageId(pendingType || role),
    role,
    content,
    result,
    attachments,
    pendingType,
    elapsedSeconds,
    consultant: normalizeAiConsultantType(consultant || aiConsultantSelectedConsultant),
    job,
    createdAt: new Date().toISOString(),
  };
  aiConsultantMessages.push(message);
  renderAiConsultantConversation({ stickToBottom: true });
  return message.localId;
}

function updateAiConsultantPendingMessage(messageId, content, options = {}) {
  if (!messageId) return;
  const message = aiConsultantMessages.find((item) => item.localId === messageId);
  if (!message || !message.pendingType) return;
  const cleanContent = String(content || "").trim();
  if (cleanContent) message.content = cleanContent;
  if (options.elapsedSeconds !== undefined) {
    message.elapsedSeconds = Math.max(0, Number(options.elapsedSeconds) || 0);
  }
  if (options.job !== undefined) {
    message.job = options.job || null;
  }
  if (options.consultant !== undefined) {
    message.consultant = normalizeAiConsultantType(options.consultant || message.consultant || aiConsultantSelectedConsultant);
  }
  const escapedMessageId = String(messageId).replace(/\\/g, "\\\\").replace(/"/g, '\\"');
  const node = aiConsultantConversation?.querySelector(`[data-message-key="${escapedMessageId}"]`);
  if (!node) {
    renderAiConsultantConversation({ stickToBottom: true });
    return;
  }
  const feedback = node.querySelector(".ai-consultant-feedback");
  if (feedback) {
    feedback.textContent = message.content;
  }
  const thinking = node.querySelector(".ai-consultant-thinking-label");
  if (thinking) {
    thinking.textContent = message.content;
  }
  if (message.pendingType === "thinking" && message.consultant === "simulation") {
    renderAiConsultantConversation({ stickToBottom: shouldAutoScrollAiConsultantConversation() });
    return;
  }
  if (shouldAutoScrollAiConsultantConversation()) {
    scrollAiConsultantConversationToBottom();
  }
}

function updateAiConsultantPendingJobStatus(jobStatus, consultant = "") {
  if (!jobStatus) return;
  const cleanConsultant = normalizeAiConsultantType(consultant || jobStatus.consultant || aiConsultantSelectedConsultant);
  const message = [...aiConsultantMessages].reverse().find((item) => item.pendingType === "thinking" && normalizeAiConsultantType(item.consultant) === cleanConsultant);
  if (!message) return;
  message.job = jobStatus;
  message.consultant = cleanConsultant;
  renderAiConsultantConversation({ stickToBottom: shouldAutoScrollAiConsultantConversation() });
}

function removeAiConsultantPendingMessages({ render = true } = {}) {
  const beforeCount = aiConsultantMessages.length;
  aiConsultantMessages = aiConsultantMessages.filter((message) => !message.pendingType);
  const changed = aiConsultantMessages.length !== beforeCount;
  if (changed && render) {
    renderAiConsultantConversation({ stickToBottom: true });
  }
  return changed;
}

async function requestAiConsultantIntentFeedback(payload, feedbackMessageId, outgoingText, attachments = []) {
  const controller = new AbortController();
  const timeoutId = window.setTimeout(() => controller.abort(), 15000);
  try {
    const response = await fetch(apiPath("/api/consultants/intent"), {
      method: "POST",
      headers: jsonHeaders(),
      signal: controller.signal,
      body: JSON.stringify(payload),
    });
    const data = await parseJsonResponseOrThrow(response, "AI 컨설턴트 의도 피드백");
    if (!response.ok || !data.ok) {
      updateAiConsultantPendingMessage(feedbackMessageId, buildAiConsultantIntentFallbackFeedback(outgoingText, attachments));
      return null;
    }
    const feedback = data.feedback || {};
    if (feedback.message) {
      updateAiConsultantPendingMessage(feedbackMessageId, feedback.message);
    }
    return feedback;
  } catch (_error) {
    updateAiConsultantPendingMessage(feedbackMessageId, buildAiConsultantIntentFallbackFeedback(outgoingText, attachments));
    return null;
  } finally {
    window.clearTimeout(timeoutId);
  }
}

async function submitAiConsultantRequest() {
  if (aiConsultantInFlight) return;
  const consultant = normalizeAiConsultantType(aiConsultantSelectedConsultant);
  const requestText = String(aiConsultantInput?.value || "").trim();
  let attachments = [];
  try {
    attachments = await readAiConsultantAttachments();
  } catch (error) {
    setAiConsultantStatus(error.message || "첨부 파일을 읽지 못했습니다.", true);
    return;
  }
  if (!requestText && !attachments.length) {
    setAiConsultantStatus("검토할 질문이나 첨부 파일을 입력해 주세요.", true);
    return;
  }

  if (!aiConsultantActiveSessionId) {
    setAiConsultantStatus("좌측의 새 세션에서 컨설턴트를 선택하거나 기존 세션을 선택해 주세요.", true);
    renderAiConsultantConversation();
    return;
  }

  const outgoingText = requestText || defaultAiConsultantAttachmentPrompt(consultant);
  const requestSessionId = aiConsultantActiveSessionId;

  if (!isAiConsultantLlmReady()) {
    setAiConsultantBusy(true);
    appendAiConsultantLocalMessage("user", outgoingText, { attachments });
    setAiConsultantStatus("LLM이 꺼져 있어 안내 메시지를 공용 세션에 저장합니다.");
    if (aiConsultantInput) aiConsultantInput.value = "";
    if (aiConsultantFileInput) aiConsultantFileInput.value = "";
    renderAiConsultantAttachmentList();
    try {
      const payload = withClientSession({
        consultant,
        message: outgoingText,
        attachments,
        writerMode: "mock",
        llmAccessToken: "",
      });
      const response = await fetch(apiPath(`/api/consultants/ux/sessions/${encodeURIComponent(requestSessionId)}/messages`), {
        method: "POST",
        headers: jsonHeaders(),
        body: JSON.stringify(payload),
      });
      const data = await parseJsonResponseOrThrow(response, `${formatAiConsultantTypeLabel(consultant)} 상담`);
      if (!response.ok || !data.ok) {
        throw new Error(data.error || "LLM 사용 안내 메시지를 저장하지 못했습니다.");
      }
      aiConsultantLatestResult = data.result || buildAiConsultantLlmRequiredResult();
      await loadAiConsultantSessions();
      if (aiConsultantActiveSessionId === requestSessionId) {
        renderAiConsultantWorkspace(data.session || {});
      } else {
        renderAiConsultantSessions();
      }
      setAiConsultantStatus("LLM이 꺼져 있어 안내 메시지를 공용 세션에 저장했습니다.");
    } catch (error) {
      const result = buildAiConsultantLlmRequiredResult();
      appendAiConsultantLocalMessage("assistant", result.answer, { result });
      aiConsultantLatestResult = result;
      setAiConsultantStatus(error.message || "LLM 사용 안내 메시지를 저장하지 못했습니다.", true);
    } finally {
      setAiConsultantBusy(false);
    }
    return;
  }

  setAiConsultantBusy(true);
  let keepBusyForPolling = false;
  const baselineMessageCount = Number(
    aiConsultantSessions.find((session) => session.sessionId === requestSessionId)?.messageCount
  ) || aiConsultantMessages.filter((messageItem) => !messageItem.localId && !messageItem.pendingType).length;
  appendAiConsultantLocalMessage("user", outgoingText, { attachments });
  const feedbackMessageId = appendAiConsultantLocalMessage("assistant", buildAiConsultantIntentPendingFeedback(), {
    pendingType: "feedback",
    consultant,
  });
  const thinkingMessageId = appendAiConsultantLocalMessage("assistant", buildAiConsultantThinkingMessage(0), {
    pendingType: "thinking",
    elapsedSeconds: 0,
    consultant,
  });
  startAiConsultantThinkingTimer(thinkingMessageId);
  if (aiConsultantInput) aiConsultantInput.value = "";
  if (aiConsultantFileInput) aiConsultantFileInput.value = "";
  renderAiConsultantAttachmentList();
  setAiConsultantStatus(`${formatAiConsultantTypeLabel(consultant)}가 검토 중입니다. 첨부와 지식 근거를 압축해 LLM에 전달합니다.`);
  try {
    const payload = await buildLlmControlledPayload({
      consultant,
      message: outgoingText,
      attachments,
    });
    if (!payload) {
      stopAiConsultantThinkingTimer();
      removeAiConsultantPendingMessages({ render: false });
      appendAiConsultantLocalMessage("assistant", "요청이 취소되어 상담을 시작하지 않았습니다.");
      setAiConsultantStatus("요청이 취소되었습니다.");
      return;
    }
    setAiConsultantStatus(`${formatAiConsultantTypeLabel(consultant)}가 요청 의도를 확인 중입니다.`);
    const intentFeedback = await requestAiConsultantIntentFeedback(payload, feedbackMessageId, outgoingText, attachments);
    if (intentFeedback?.message) {
      payload.intentFeedback = intentFeedback;
    }
    setAiConsultantStatus(`${formatAiConsultantTypeLabel(consultant)}가 답변을 생성 중입니다.`);
    const response = await fetch(apiPath(`/api/consultants/ux/sessions/${encodeURIComponent(requestSessionId)}/messages`), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(payload),
    });
    const data = await parseJsonResponseOrThrow(response, `${formatAiConsultantTypeLabel(consultant)} 상담`);
    if (!response.ok || !data.ok) {
      throw new Error(data.error || `${formatAiConsultantTypeLabel(consultant)} 응답을 생성하지 못했습니다.`);
    }
    if (data.pending) {
      keepBusyForPolling = true;
      updateAiConsultantPendingMessage(thinkingMessageId, buildAiConsultantThinkingMessage(0), {
        consultant,
        job: data.job || null,
      });
      setAiConsultantStatus(`${formatAiConsultantTypeLabel(consultant)}가 답변을 생성 중입니다.`);
      pollAiConsultantPendingResponse({
        sessionId: requestSessionId,
        consultant,
        jobId: data.job?.jobId || "",
        baselineMessageCount,
        startedAt: Date.now(),
      });
      return;
    }
    stopAiConsultantThinkingTimer();
    aiConsultantLatestResult = data.result || null;
    await loadAiConsultantSessions();
    if (aiConsultantActiveSessionId === requestSessionId) {
      renderAiConsultantWorkspace(data.session || {});
    } else {
      renderAiConsultantSessions();
    }
    if (data.context?.llmError) {
      setAiConsultantStatus("LLM 답변 생성 오류 안내를 공용 세션에 저장했습니다.", true);
      trackUserEvent("ai_consultant_failed", {
        consultant,
        persisted: true,
        attachmentCount: attachments.length,
        knowledgeRefCount: data.context?.knowledgeRefs?.length || 0,
      });
    } else {
      setAiConsultantStatus(`${formatAiConsultantTypeLabel(consultant)} 상담 응답을 저장했습니다.`);
      trackUserEvent("ai_consultant_completed", {
        consultant,
        usedLlm: true,
        attachmentCount: attachments.length,
        knowledgeRefCount: data.context?.knowledgeRefs?.length || 0,
      });
    }
  } catch (error) {
    stopAiConsultantThinkingTimer();
    removeAiConsultantPendingMessages({ render: false });
    appendAiConsultantLocalMessage("assistant", error.message || `${formatAiConsultantTypeLabel(consultant)} 요청 중 오류가 발생했습니다.`, {
      result: {
        summary: "요청 처리 실패",
        answer: error.message || `${formatAiConsultantTypeLabel(consultant)} 요청 중 오류가 발생했습니다.`,
      },
    });
    setAiConsultantStatus(error.message || `${formatAiConsultantTypeLabel(consultant)} 요청 중 오류가 발생했습니다.`, true);
    trackUserEvent("ai_consultant_failed", { consultant, error: error.message || String(error) });
  } finally {
    if (!keepBusyForPolling) {
      setAiConsultantBusy(false);
    }
  }
}

form.addEventListener("submit", async (event) => {
  event.preventDefault();
  if (!guardWritePermission("조회 권한은 새 문서 작성을 실행할 수 없습니다.")) {
    return;
  }
  const formData = new FormData(form);
  const topic = getCurrentRequestTopic(formData);
  if (!topic) {
    setMessage("좌측에서 작성할 정책서 주제를 먼저 선택해 주세요.", true);
    return;
  }
  const rewriteExisting = isRewriteRequestForTopic(topic);
  const templateType = formData.get("templateType") || "simple";
  if (rewriteExisting && !guardPolicyAdminAction("정책서 다시 작성은 관리자만 실행할 수 있습니다.")) {
    return;
  }
  if (templateType === "full" && !guardPolicyAdminAction("Full 버전 작성은 관리자만 실행할 수 있습니다.")) {
    return;
  }

  setMessage("정책서 생성 작업을 시작합니다.");
  setSubmitButtonsDisabled(true);

  const writerMode = getSelectedWriterMode();
  try {
    const allowed = await ensureWriterModeAccess(writerMode);
    if (!allowed) {
      setSubmitButtonsDisabled(false);
      return;
    }
  } catch (error) {
    setSubmitButtonsDisabled(false);
    setMessage(error.message || "LLM 사용 인증에 실패했습니다.", true);
    return;
  }

  const payload = {
    topic,
    templateType,
    reviewMode: formData.get("reviewMode") || "auto",
    inspectionMode: formData.get("inspectionMode") || "chapter-final",
    writerMode,
    llmAccessToken: writerMode === "llm" ? llmAccessToken : "",
    brief: formData.get("brief"),
    author: formData.get("author"),
    status: formData.get("status"),
    rewriteExisting,
  };

  try {
    const response = await fetch(apiPath("/api/policies"), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession(payload)),
    });
    const data = await parseJsonResponseOrThrow(response, "정책서 생성");
    if (!response.ok || !data.ok) {
      throw new Error(data.error || "정책서 생성에 실패했습니다.");
    }
    if (data.job) {
      activeJobId = data.job.id;
      clearRewriteRequest();
      openProgressModal(data.job);
      setMessage("정책서 생성이 진행 중입니다. 작성 현황 팝업에서 단계를 확인하세요.");
      startProgressPolling(activeJobId);
      return;
    }
    clearRewriteRequest();
    setMessage(`생성 완료: ${data.item.name}`);
    await loadPolicies(data.item.name);
  } catch (error) {
    setMessage(error.message, true);
    setSubmitButtonsDisabled(false);
    closeProgressPolling();
  }
});

progressCloseButton?.addEventListener("click", () => {
  closeOrCancelProgressModal();
});

progressCancelButton?.addEventListener("click", () => {
  closeOrCancelProgressModal();
});

function startProgressPolling(jobId) {
  closeProgressPolling();
  progressTimer = window.setInterval(() => pollJob(jobId), 1000);
  startProgressHeartbeat(jobId);
  pollJob(jobId);
}

function shouldReconnectAutoPilotJob(job) {
  return Boolean(job?.id && job?.kind === "auto_pilot" && isProgressBusy(job));
}

async function reconnectActiveAutoPilotForSelectedPolicy(name = selectedName) {
  const cleanName = String(name || "").trim();
  if (!cleanName || selectedDraft) return false;
  if (progressTimer && currentProgressJob?.kind === "auto_pilot") return false;
  if (autoPilotReconnectInFlightName === cleanName) return false;
  autoPilotReconnectInFlightName = cleanName;
  try {
    const response = await fetch(
      apiPath(`/api/jobs/active?kind=auto_pilot&name=${encodeURIComponent(cleanName)}`),
      { cache: "no-store", headers: jsonHeaders() }
    );
    const data = await parseJsonResponseOrThrow(response, "진행 중인 Auto Pilot");
    if (!response.ok || !data.ok || !shouldReconnectAutoPilotJob(data.job)) return false;
    if (selectedName !== cleanName) return false;
    activeJobId = data.job.id;
    openProgressModal(data.job);
    startProgressPolling(activeJobId);
    setMessage("진행 중인 Auto Pilot 작업에 다시 연결했습니다. 명시적으로 중단하지 않으면 서버에서 계속 진행됩니다.");
    return true;
  } catch (error) {
    console.warn("Auto Pilot reconnect failed.", error);
    return false;
  } finally {
    if (autoPilotReconnectInFlightName === cleanName) {
      autoPilotReconnectInFlightName = "";
    }
  }
}

function closeProgressPolling() {
  if (progressTimer) {
    window.clearInterval(progressTimer);
    progressTimer = null;
  }
  if (progressHeartbeatTimer) {
    window.clearInterval(progressHeartbeatTimer);
    progressHeartbeatTimer = null;
  }
}

function startProgressHeartbeat(jobId) {
  if (!jobId) return;
  sendJobHeartbeat(jobId);
  progressHeartbeatTimer = window.setInterval(() => sendJobHeartbeat(jobId), JOB_HEARTBEAT_INTERVAL_MS);
}

async function sendJobHeartbeat(jobId) {
  if (!jobId) return;
  try {
    await fetch(apiPath(`/api/jobs/${encodeURIComponent(jobId)}/heartbeat`), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession({ active: true })),
      keepalive: true,
    });
  } catch (error) {
    // The server watchdog will cancel orphaned work if heartbeats stop.
  }
}

async function closeOrCancelProgressModal() {
  const job = currentProgressJob;
  if (!job || !isCancelableJob(job)) {
    progressModal.hidden = true;
    return;
  }
  if (!guardWritePermission("조회 권한은 진행 중 작업 중단을 실행할 수 없습니다.")) return;

  const jobKind = String(job.kind || "");
  const confirmText = jobKind === "auto_pilot"
    ? "Auto Pilot 작업을 중단할까요?\n진행 중인 LLM 호출 결과가 뒤늦게 도착해도 문서에 저장하지 않습니다."
    : jobKind === "revision"
      ? "문서 보완 작업을 중단할까요?\n진행 중인 LLM 호출 결과가 뒤늦게 도착해도 문서에 반영하지 않습니다."
      : "정책서 작성을 중단할까요?\n사용자 검토 대기 중이면 즉시 멈추고, LLM 호출 중이면 현재 호출이 끝난 직후 중단됩니다.\n지금까지 작성된 중간 결과와 체크포인트는 보관됩니다.";
  const confirmed = window.confirm(
    confirmText
  );
  if (!confirmed) return;

  progressCloseButton.disabled = true;
  if (progressCancelButton) progressCancelButton.disabled = true;
  const cancelingMessage = jobKind === "auto_pilot"
    ? "Auto Pilot 중단을 요청했습니다. 저장되지 않도록 정리합니다."
    : jobKind === "revision"
      ? "문서 보완 중단을 요청했습니다. 저장되지 않도록 정리합니다."
      : "정책서 생성 중단을 요청했습니다. 중간 결과를 보관합니다.";
  setMessage(cancelingMessage);
  try {
    const response = await fetch(apiPath(`/api/jobs/${encodeURIComponent(job.id)}/cancel`), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession({ reason: "progress_modal_closed" })),
    });
    const data = await parseJsonResponseOrThrow(response, "작업 중단");
    if (!response.ok || !data.ok) {
      throw new Error(data.error || "작업 중단에 실패했습니다.");
    }
    currentProgressJob = data.job;
    progressModal.hidden = true;
    if (data.job?.status === "canceled") {
      closeProgressPolling();
      setSubmitButtonsDisabled(false);
      revisionButton.disabled = false;
      if (autoPilotButton) autoPilotButton.disabled = false;
      setMessage(data.job.message || "정책서 작업이 중단되었습니다.");
    } else {
      startProgressPolling(job.id);
      setMessage(jobKind === "auto_pilot"
        ? "Auto Pilot 중단을 요청했습니다. 실행 중인 호출을 정리하는 동안 잠시만 기다려 주세요."
        : "정책서 작업 중단을 요청했습니다. 보관 상태로 전환하는 동안 잠시만 기다려 주세요.");
    }
    await loadPolicies(selectedName, { autoSelect: false });
    const draft = latestDraftForTopic(data.job?.topic || job.topic);
    if (draft) {
      selectDraft(draft);
    } else if (!selectedName || !currentItems.some((item) => item.name === selectedName)) {
      clearPreview();
    }
  } catch (error) {
    setMessage(error.message, true);
  } finally {
    progressCloseButton.disabled = false;
    if (progressCancelButton) progressCancelButton.disabled = false;
  }
}

function isCancelableJob(job) {
  return ["queued", "running", "waiting_review", "review", "retry"].includes(job.status);
}

async function pollJob(jobId) {
  try {
    const response = await fetch(apiPath(`/api/jobs/${encodeURIComponent(jobId)}`));
    const data = await parseJsonResponseOrThrow(response, "작업 상태");
    if (!response.ok || !data.ok) {
      throw new Error(data.error || "작업 상태를 불러오지 못했습니다.");
    }
    renderProgress(data.job);
    if (data.job.status === "completed") {
      closeProgressPolling();
      setSubmitButtonsDisabled(false);
      revisionButton.disabled = false;
      if (autoPilotButton) autoPilotButton.disabled = false;
      if (selectionRevisionSubmitButton) selectionRevisionSubmitButton.disabled = false;
      revisionRequest.value = "";
      const doneLabel = data.job.kind === "auto_pilot"
        ? "Auto Pilot 완료"
        : data.job.kind === "revision"
          ? "수정 완료"
          : "생성 완료";
      const resultName = data.job.result?.name || "정책서";
      const policyCardQuality = data.job.result?.policyCardQuality;
      const policyCardSuffix = policyCardQuality?.applicable
        ? ` · 정책카드 ${Number(policyCardQuality.score || 0)}점${policyCardQuality.passed ? "" : " 미달"}`
        : "";
      const reviewSuffix = data.job.kind === "auto_pilot" && data.job.result?.needsReview
        ? ` · 남은 확인 필요 ${Number(data.job.result?.remainingWorkItems?.length || data.job.result?.remainingItems?.length || 0)}건`
        : "";
      setMessage(`${doneLabel}: ${resultName}${policyCardSuffix}${reviewSuffix}`);
      if (data.job.result?.name) {
        await loadPolicies(data.job.result.name);
        if (data.job.kind === "revision" && pendingQaActionCheck) {
          if (pendingQaActionCheck.report) {
            qaReviewReportsByPolicy.set(data.job.result.name, pendingQaActionCheck.report);
            latestQaReviewReport = pendingQaActionCheck.report;
          }
          await checkDocumentQaActionStatus({ name: data.job.result.name, items: pendingQaActionCheck.items, manual: false });
          pendingQaActionCheck = null;
        }
      } else {
        await loadPolicies();
      }
    }
    if (data.job.status === "canceled") {
      closeProgressPolling();
      setSubmitButtonsDisabled(false);
      revisionButton.disabled = false;
      if (autoPilotButton) autoPilotButton.disabled = false;
      if (selectionRevisionSubmitButton) selectionRevisionSubmitButton.disabled = false;
      setMessage(data.job.message || "작업이 중단되었습니다.");
      await loadPolicies(selectedName, { autoSelect: false });
      const draft = latestDraftForTopic(data.job.topic);
      if (draft) {
        selectDraft(draft);
      }
    }
    if (data.job.status === "error") {
      closeProgressPolling();
      setSubmitButtonsDisabled(false);
      revisionButton.disabled = false;
      if (autoPilotButton) autoPilotButton.disabled = false;
      if (selectionRevisionSubmitButton) selectionRevisionSubmitButton.disabled = false;
      setMessage(data.job.error || data.job.message || "작업 중 오류가 발생했습니다.", true);
    }
  } catch (error) {
    closeProgressPolling();
    setSubmitButtonsDisabled(false);
    revisionButton.disabled = false;
    if (autoPilotButton) autoPilotButton.disabled = false;
    if (selectionRevisionSubmitButton) selectionRevisionSubmitButton.disabled = false;
    if (isMissingJobStatusError(error)) {
      activeJobId = "";
      currentProgressJob = null;
      progressModal.hidden = true;
      setMessage("작업 상태 기록이 만료되어 목록을 새로고침했습니다.");
      await loadPolicies(selectedName, { autoSelect: false });
      return;
    }
    setMessage(error.message, true);
  } finally {
  }
}

function workspaceAiChatJobStage(job) {
  return (job?.stages || []).find((stage) => stage.key === job?.currentStageKey) || null;
}

const WORKSPACE_REVISION_AGENT_STAGES = [
  { key: "00", name: "intent", label: "수정 의도 분석" },
  { key: "01", name: "revise", label: "수정 Agent" },
  { key: "02", name: "inspect", label: "수정본 검수" },
  { key: "03", name: "history", label: "문서 히스토리 업데이트" },
  { key: "04", name: "save", label: "수정본 저장" },
];

function normalizeWorkspaceAiChatJobStages(job) {
  const stages = Array.isArray(job?.stages) ? job.stages : [];
  return stages
    .filter((stage) => stage && typeof stage === "object")
    .slice(0, 12)
    .map((stage, index) => ({
      key: cleanWorkspaceText(stage.key || `${index}`),
      name: cleanWorkspaceText(stage.name || ""),
      label: cleanWorkspaceText(stage.label || stage.name || `단계 ${index + 1}`),
      status: cleanWorkspaceText(stage.status || "pending"),
      attempt: Number(stage.attempt || 0) || 0,
      score: stage.score ?? null,
      threshold: stage.threshold ?? null,
      durationMs: Number(stage.durationMs || 0) || 0,
      message: cleanWorkspaceMultilineText(stage.message || ""),
    }));
}

function workspaceAiChatRevisionChangeSummary(message) {
  return cleanWorkspaceMultilineText(message?.changeSummary || message?.change_summary || "");
}

function workspaceAiChatJobSignature(job) {
  const currentStage = workspaceAiChatJobStage(job);
  const status = String(job?.status || "");
  const review = job?.manualReview || {};
  const elapsedBucket = status === "waiting_review" ? "" : Math.floor(Number(job?.elapsedMs || 0) / 60000);
  return [
    status,
    job?.currentStageKey || "",
    currentStage?.status || "",
    currentStage?.score ?? "",
    currentStage?.message || "",
    review?.id || "",
    review?.reviewType || "",
    review?.score ?? "",
    review?.threshold ?? "",
    job?.message || "",
    job?.result?.name || "",
    job?.result?.changeSummary || job?.changeSummary || "",
    job?.error || "",
    elapsedBucket,
  ].join("|");
}

function workspaceAiChatJobStatusBody(job) {
  const status = String(job?.status || "");
  const currentStage = workspaceAiChatJobStage(job);
  const review = job?.manualReview || {};
  const stageLabel = progressDisplayText(currentStage?.label || statusLabel(status));
  const elapsed = job?.elapsedMs ? ` · 경과 ${formatDuration(job.elapsedMs)}` : "";
  const scoreText = review?.score !== undefined && review?.score !== null
    ? ` 점수 ${review.score}점${review?.threshold !== undefined && review?.threshold !== null ? ` / 기준 ${review.threshold}점` : ""}.`
    : "";
  if (status === "completed") {
    const resultName = cleanWorkspaceText(job?.result?.name || "");
    const changeSummary = cleanWorkspaceMultilineText(job?.result?.changeSummary || job?.changeSummary || "");
    const lines = ["수정 작업이 완료되었습니다."];
    lines.push(resultName ? `새 결과는 ${resultName}입니다.` : "정책서 목록을 새로고침했습니다.");
    if (changeSummary) {
      lines.push("", "수정 내용:", changeSummary);
    }
    return lines.join("\n");
  }
  if (status === "error") {
    return `수정 작업 중 오류가 발생했습니다. ${progressDisplayText(job?.error || job?.message || "오류 내용을 확인해 주세요.")}`;
  }
  if (status === "canceled" || status === "cancelled") {
    return progressDisplayText(job?.message || "수정 작업이 중단되었습니다.");
  }
  if (status === "waiting_review") {
    return `수정본 검수가 끝났고 저장 여부 확인을 기다리고 있습니다.${scoreText} 현재 단계: ${stageLabel}${elapsed}\n작업이 멈춘 것이 아니라 아래 버튼 선택을 기다리는 상태입니다.`;
  }
  return `수정 작업을 진행 중입니다. 현재 단계: ${stageLabel}${elapsed}`;
}

function workspaceAiChatJobReviewActions(job) {
  if (String(job?.status || "") !== "waiting_review") return [];
  const reviewType = String(job?.manualReview?.reviewType || "");
  if (reviewType !== "revision_inspection_gate") {
    return [{ action: "continue", label: "이어서 진행", variant: "primary" }];
  }
  return [
    { action: "continue", label: "점수 확인 후 저장", variant: "primary" },
    { action: "stop", label: "저장하지 않고 중단", variant: "danger" },
  ];
}

function workspaceAiChatJobTone(job) {
  const status = String(job?.status || "").trim().toLowerCase();
  if (status === "completed") return "good";
  if (["error", "failed", "aborted", "canceled", "cancelled"].includes(status)) return "warn";
  if (status === "waiting_review" || status === "review") return "review";
  return "progress";
}

function workspaceAiChatJobStatusLabel(status) {
  const value = cleanWorkspaceText(status || "").toLowerCase();
  if (value === "completed") return "완료";
  if (value === "waiting_review" || value === "review") return "검수 대기";
  if (value === "canceled" || value === "cancelled" || value === "aborted") return "중단";
  if (value === "canceling") return "중단 중";
  if (value === "error" || value === "failed") return "오류";
  if (value === "queued") return "대기";
  return "진행 중";
}

function workspaceAiChatJobCanRestartStatus(status) {
  return ["canceled", "cancelled", "aborted", "error", "failed"].includes(cleanWorkspaceText(status || "").toLowerCase());
}

function workspaceAiChatJobIsActive(status) {
  return ["queued", "running", "waiting_review", "review", "retry", "canceling"].includes(String(status || ""));
}

function workspaceAiChatJobCanCancel(status) {
  return ["queued", "running", "waiting_review", "review", "retry"].includes(String(status || ""));
}

function workspaceAiChatJobElapsedIsLive(status) {
  return ["queued", "running", "retry", "canceling"].includes(cleanWorkspaceText(status || "").toLowerCase());
}

function workspaceAiChatJobElapsedAnchorKey(message) {
  return cleanWorkspaceText(message?.jobId || message?.id || "");
}

function setWorkspaceAiChatJobElapsedAnchor(jobId, elapsedMs, status) {
  const key = cleanWorkspaceText(jobId || "");
  if (!key) return;
  const normalizedStatus = cleanWorkspaceText(status || "").toLowerCase();
  const baseMs = Math.max(0, Number(elapsedMs || 0) || 0);
  workspaceAiChatJobElapsedAnchors.set(key, {
    baseMs,
    capturedAt: Date.now(),
    status: normalizedStatus,
  });
}

function workspaceAiChatJobElapsedForMessage(message) {
  const key = workspaceAiChatJobElapsedAnchorKey(message);
  const status = workspaceAiChatJobStatusFromMessage(message);
  const baseMs = Math.max(0, Number(message?.elapsedMs || 0) || 0);
  if (!key || !workspaceAiChatJobElapsedIsLive(status)) return baseMs;
  let anchor = workspaceAiChatJobElapsedAnchors.get(key);
  if (!anchor || anchor.status !== status) {
    setWorkspaceAiChatJobElapsedAnchor(key, baseMs, status);
    anchor = workspaceAiChatJobElapsedAnchors.get(key);
  }
  return Math.max(0, Number(anchor?.baseMs || 0) + (Date.now() - Number(anchor?.capturedAt || Date.now())));
}

function workspaceAiChatJobShouldShowElapsed(message, status, elapsedMs) {
  return workspaceAiChatJobElapsedIsLive(status) || Number(elapsedMs || 0) > 0 || Number(message?.elapsedMs || 0) > 0;
}

function workspaceAiChatJobStatusText(statusLabel, elapsedMs, showElapsed) {
  return `상태 · ${statusLabel}${showElapsed ? ` · ${formatDuration(elapsedMs)}` : ""}`;
}

function findWorkspaceAiChatMessageByJobId(jobId) {
  const targetJobId = cleanWorkspaceText(jobId || "");
  if (!targetJobId) return null;
  for (let index = workspaceAiChatMessages.length - 1; index >= 0; index -= 1) {
    const message = workspaceAiChatMessages[index];
    if (message?.role === "assistant" && cleanWorkspaceText(message.jobId || "") === targetJobId) {
      return message;
    }
  }
  return null;
}

function stopWorkspaceAiChatJobElapsedTimer() {
  if (workspaceAiChatJobElapsedTimer) {
    window.clearInterval(workspaceAiChatJobElapsedTimer);
  }
  workspaceAiChatJobElapsedTimer = null;
}

function refreshWorkspaceAiChatJobElapsedDisplays() {
  if (!workspaceAiChatList) {
    stopWorkspaceAiChatJobElapsedTimer();
    return;
  }
  const nodes = [...workspaceAiChatList.querySelectorAll("[data-workspace-agent-elapsed='true']")];
  let hasLiveElapsed = false;
  nodes.forEach((node) => {
    const jobId = node.getAttribute("data-workspace-agent-job-id") || "";
    const message = findWorkspaceAiChatMessageByJobId(jobId);
    if (!message) return;
    const status = workspaceAiChatJobStatusFromMessage(message);
    const elapsed = workspaceAiChatJobElapsedForMessage(message);
    if (workspaceAiChatJobElapsedIsLive(status)) hasLiveElapsed = true;
    const statusLabel = workspaceAiChatJobStatusLabel(status);
    node.textContent = workspaceAiChatJobStatusText(
      statusLabel,
      elapsed,
      workspaceAiChatJobShouldShowElapsed(message, status, elapsed)
    );
  });
  if (!hasLiveElapsed) {
    stopWorkspaceAiChatJobElapsedTimer();
  }
}

function scheduleWorkspaceAiChatJobElapsedTimer() {
  const hasLiveElapsed = workspaceAiChatMessages.some((message) => (
    isWorkspaceAiChatJobPanelMessage(message) &&
    workspaceAiChatJobElapsedIsLive(workspaceAiChatJobStatusFromMessage(message))
  ));
  if (!hasLiveElapsed) {
    stopWorkspaceAiChatJobElapsedTimer();
    return;
  }
  refreshWorkspaceAiChatJobElapsedDisplays();
  if (!workspaceAiChatJobElapsedTimer) {
    workspaceAiChatJobElapsedTimer = window.setInterval(refreshWorkspaceAiChatJobElapsedDisplays, 1000);
  }
}

function latestWorkspaceAiChatJobIdFromMessages() {
  for (let index = workspaceAiChatMessages.length - 1; index >= 0; index -= 1) {
    const message = workspaceAiChatMessages[index];
    const jobId = cleanWorkspaceText(message?.jobId || "");
    const tone = cleanWorkspaceText(message?.tone || "");
    if (jobId && ["progress", "review"].includes(tone)) {
      return jobId;
    }
  }
  return "";
}

async function resumeWorkspaceAiChatJobFromMessages() {
  if (isWorkspaceAiChatWorking()) return;
  const jobId = latestWorkspaceAiChatJobIdFromMessages();
  if (!jobId) return;
  try {
    const response = await fetch(apiPath(`/api/jobs/${encodeURIComponent(jobId)}`), { cache: "no-store" });
    const data = await parseJsonResponseOrThrow(response, "대화형 수정 작업 상태");
    if (!response.ok || !data.ok || !data.job) return;
    if (workspaceAiChatJobIsActive(data.job.status)) {
      startWorkspaceAiChatJobTracking(data.job);
    }
  } catch (error) {
    // 오래된 대화에 남은 jobId일 수 있으므로 조용히 무시합니다.
  }
}

function updateWorkspaceAiChatActiveJob(job) {
  const jobId = cleanWorkspaceText(job?.id || "");
  const status = cleanWorkspaceText(job?.status || "");
  if (!jobId) return;
  if (workspaceAiChatJobIsActive(status)) {
    workspaceAiChatActiveJobId = jobId;
    workspaceAiChatActiveJobStatus = status;
    if (status === "canceling") {
      workspaceAiChatCancelingJobIds.add(jobId);
    }
    return;
  }
  if (workspaceAiChatActiveJobId === jobId) {
    workspaceAiChatActiveJobId = "";
    workspaceAiChatActiveJobStatus = "";
  }
  workspaceAiChatCancelingJobIds.delete(jobId);
}

function appendWorkspaceAiChatJobStatus(job, options = {}) {
  if (!job?.id) return;
  updateWorkspaceAiChatActiveJob(job);
  const signature = workspaceAiChatJobSignature(job);
  if (!options.force && workspaceAiChatJobSignatures.get(job.id) === signature) return;
  workspaceAiChatJobSignatures.set(job.id, signature);
  upsertWorkspaceAiChatJobStatusMessage(job);
}

function findWorkspaceAiChatJobMessageIndex(jobId) {
  const targetJobId = cleanWorkspaceText(jobId || "");
  if (!targetJobId) return -1;
  for (let index = workspaceAiChatMessages.length - 1; index >= 0; index -= 1) {
    const message = workspaceAiChatMessages[index];
    if (message?.role === "assistant" && cleanWorkspaceText(message.jobId || "") === targetJobId) {
      return index;
    }
  }
  return -1;
}

function findWorkspaceAiChatMessageIndex(message) {
  const messageId = cleanWorkspaceText(message?.id || "");
  const jobId = cleanWorkspaceText(message?.jobId || "");
  for (let index = workspaceAiChatMessages.length - 1; index >= 0; index -= 1) {
    const item = workspaceAiChatMessages[index];
    if (messageId && cleanWorkspaceText(item?.id || "") === messageId) return index;
    if (jobId && cleanWorkspaceText(item?.jobId || "") === jobId) return index;
  }
  return -1;
}

function workspaceAiChatRestartInstruction(message) {
  const direct = cleanWorkspaceText(message?.restartInstruction || message?.restart_instruction || "");
  if (direct) return direct;
  const messageIndex = findWorkspaceAiChatMessageIndex(message);
  const startIndex = messageIndex >= 0 ? messageIndex - 1 : workspaceAiChatMessages.length - 1;
  for (let index = startIndex; index >= 0; index -= 1) {
    const instruction = workspaceAiChatRevisionInstruction(workspaceAiChatMessages[index]);
    if (instruction) return instruction;
  }
  return "";
}

function upsertWorkspaceAiChatJobStatusMessage(job) {
  const jobId = cleanWorkspaceText(job?.id || "");
  if (!jobId) return "";
  const now = new Date().toISOString();
  setWorkspaceAiChatJobElapsedAnchor(jobId, job?.elapsedMs, job?.status);
  const existingIndex = findWorkspaceAiChatJobMessageIndex(jobId);
  const existing = existingIndex >= 0 ? workspaceAiChatMessages[existingIndex] : null;
  const actions = normalizeWorkspaceAiChatActions(workspaceAiChatJobReviewActions(job));
  const nextMessage = {
    ...existing,
    id: existing?.id || editorAssistId("chat"),
    role: "assistant",
    body: workspaceAiChatJobStatusBody(job),
    meta: "수정 Agent",
    tone: workspaceAiChatJobTone(job),
    jobId,
    jobStatus: cleanWorkspaceText(job.status || ""),
    currentStageKey: cleanWorkspaceText(job.currentStageKey || ""),
    elapsedMs: Number(job.elapsedMs || 0) || 0,
    resultName: cleanWorkspaceText(job?.result?.name || ""),
    changeSummary: cleanWorkspaceMultilineText(job?.result?.changeSummary || job?.changeSummary || existing?.changeSummary || ""),
    jobMessage: cleanWorkspaceMultilineText(job.message || ""),
    jobError: cleanWorkspaceMultilineText(job.error || ""),
    restartInstruction: cleanWorkspaceMultilineText(job.restartInstruction || job.workspaceChatInstruction || existing?.restartInstruction || ""),
    restartSource: cleanWorkspaceText(job.restartSource || job.revisionSource || existing?.restartSource || ""),
    stages: normalizeWorkspaceAiChatJobStages(job),
    createdAt: existing?.createdAt || now,
    updatedAt: now,
  };
  delete nextMessage.revisionInstruction;
  delete nextMessage.replyKind;
  delete nextMessage.applyPending;
  delete nextMessage.appliedAt;
  if (!nextMessage.changeSummary) {
    delete nextMessage.changeSummary;
  }
  if (actions.length) {
    nextMessage.actions = actions;
  } else {
    delete nextMessage.actions;
  }
  if (existingIndex >= 0) {
    workspaceAiChatMessages.splice(existingIndex, 1, nextMessage);
  } else {
    workspaceAiChatMessages.push(nextMessage);
  }
  workspaceAiChatMessages = collapseWorkspaceAiChatJobMessages(workspaceAiChatMessages);
  saveWorkspaceAiChatMessages();
  renderWorkspaceAiChat();
  return nextMessage.id;
}

function closeWorkspaceAiChatJobTracking(jobId) {
  const pollTimer = workspaceAiChatJobTimers.get(jobId);
  if (pollTimer) window.clearInterval(pollTimer);
  workspaceAiChatJobTimers.delete(jobId);
  const heartbeatTimer = workspaceAiChatJobHeartbeatTimers.get(jobId);
  if (heartbeatTimer) window.clearInterval(heartbeatTimer);
  workspaceAiChatJobHeartbeatTimers.delete(jobId);
  workspaceAiChatJobSignatures.delete(jobId);
  if (!jobId || workspaceAiChatActiveJobId === jobId) {
    workspaceAiChatActiveJobId = "";
    workspaceAiChatActiveJobStatus = "";
  }
  if (jobId) {
    workspaceAiChatCancelingJobIds.delete(jobId);
  }
  configureWorkspaceAiChatSendButton();
  renderWorkspaceAiChatAttachmentList();
}

function startWorkspaceAiChatJobTracking(job) {
  const jobId = job?.id;
  if (!jobId) return;
  closeWorkspaceAiChatJobTracking(jobId);
  updateWorkspaceAiChatActiveJob(job);
  appendWorkspaceAiChatJobStatus(job, { force: true });
  sendJobHeartbeat(jobId);
  workspaceAiChatJobStarting = false;
  workspaceAiChatJobHeartbeatTimers.set(
    jobId,
    window.setInterval(() => sendJobHeartbeat(jobId), JOB_HEARTBEAT_INTERVAL_MS)
  );
  workspaceAiChatJobTimers.set(
    jobId,
    window.setInterval(() => pollWorkspaceAiChatJob(jobId), 2000)
  );
  renderWorkspaceAiChat();
  pollWorkspaceAiChatJob(jobId);
}

async function pollWorkspaceAiChatJob(jobId) {
  try {
    const response = await fetch(apiPath(`/api/jobs/${encodeURIComponent(jobId)}`), { cache: "no-store" });
    const data = await parseJsonResponseOrThrow(response, "대화형 수정 작업 상태");
    if (!response.ok || !data.ok) {
      throw new Error(data.error || "대화형 수정 작업 상태를 불러오지 못했습니다.");
    }
    const job = data.job;
    appendWorkspaceAiChatJobStatus(job);
    if (job.status === "completed") {
      closeWorkspaceAiChatJobTracking(jobId);
      if (revisionButton) revisionButton.disabled = false;
      setMessage(`수정 완료: ${job.result?.name || "정책서"}`);
      if (job.result?.name) {
        await loadPolicies(job.result.name);
      } else {
        await loadPolicies(selectedName, { autoSelect: false });
      }
    }
    if (job.status === "canceled" || job.status === "cancelled") {
      closeWorkspaceAiChatJobTracking(jobId);
      if (revisionButton) revisionButton.disabled = false;
      setMessage(job.message || "수정 작업이 중단되었습니다.");
      await loadPolicies(selectedName, { autoSelect: false });
    }
    if (job.status === "error") {
      closeWorkspaceAiChatJobTracking(jobId);
      if (revisionButton) revisionButton.disabled = false;
      setMessage(job.error || job.message || "수정 작업 중 오류가 발생했습니다.", true);
    }
  } catch (error) {
    closeWorkspaceAiChatJobTracking(jobId);
    if (revisionButton) revisionButton.disabled = false;
    if (isMissingJobStatusError(error)) {
      appendWorkspaceAiChatJobStatus({
        id: jobId,
        status: "error",
        error: "수정 작업 상태 기록이 만료되어 정책서 목록을 새로고침했습니다.",
      }, { force: true });
      await loadPolicies(selectedName, { autoSelect: false });
      return;
    }
    appendWorkspaceAiChatJobStatus({
      id: jobId,
      status: "error",
      error: error.message || "수정 작업 상태 확인 중 오류가 발생했습니다.",
    }, { force: true });
    setMessage(error.message || "수정 작업 상태 확인 중 오류가 발생했습니다.", true);
  }
}

async function submitWorkspaceAiChatJobReview(jobId, action, sourceButton = null) {
  if (!jobId || !action) return;
  if (!guardWritePermission("조회 권한은 수동 검수 응답을 실행할 수 없습니다.")) return;
  const actionGroup = sourceButton?.closest(".workspace-ai-chat-message-actions");
  const actionButtons = actionGroup
    ? [...actionGroup.querySelectorAll("button")]
    : sourceButton
    ? [sourceButton]
    : [];
  actionButtons.forEach((button) => {
    button.disabled = true;
  });
  try {
    const response = await fetch(apiPath(`/api/jobs/${encodeURIComponent(jobId)}/review`), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession({ action })),
    });
    const data = await parseJsonResponseOrThrow(response, "공동작업 검수 응답");
    if (!response.ok || !data.ok) {
      throw new Error(data.error || "검수 응답을 전달하지 못했습니다.");
    }
    appendWorkspaceAiChatMessage(
      "assistant",
      action === "stop" ? "수정본 저장 중단 요청을 전달했습니다." : "수정본 저장을 계속 진행하도록 요청했습니다.",
      { meta: "수정 Agent", tone: action === "stop" ? "warn" : "progress" }
    );
    if (data.job) {
      appendWorkspaceAiChatJobStatus(data.job, { force: true });
      startWorkspaceAiChatJobTracking(data.job);
    } else {
      pollWorkspaceAiChatJob(jobId);
    }
    setMessage(action === "stop" ? "수정본 저장을 중단했습니다." : "다음 단계 진행을 요청했습니다.");
  } catch (error) {
    actionButtons.forEach((button) => {
      button.disabled = false;
    });
    appendWorkspaceAiChatMessage("assistant", error.message || "검수 응답 전달 중 오류가 발생했습니다.", {
      meta: "수정 Agent",
      tone: "warn",
    });
    setMessage(error.message || "검수 응답 전달 중 오류가 발생했습니다.", true);
  }
}

async function restartWorkspaceAiChatRevisionJobMessage(jobId, sourceButton = null) {
  if (!jobId || isWorkspaceAiChatWorking()) return;
  const messageIndex = findWorkspaceAiChatJobMessageIndex(jobId);
  const message = messageIndex >= 0 ? workspaceAiChatMessages[messageIndex] : null;
  const restartInstruction = workspaceAiChatRestartInstruction(message);
  if (!message || !restartInstruction) {
    appendWorkspaceAiChatMessage("assistant", "다시 실행할 수정 요청을 찾지 못했습니다. 수정/보완 방향을 한 번 더 얘기해 주세요.", {
      meta: "수정 Agent",
      tone: "warn",
    });
    return;
  }
  if (!canCurrentUserWritePolicies()) {
    setMessage("조회 권한이라 수정 Agent를 다시 실행할 수 없습니다.", true);
    appendWorkspaceAiChatMessage("assistant", "현재 계정은 조회 권한이라 수정 Agent를 다시 실행할 수 없습니다. 편집 권한으로 전환한 뒤 다시 눌러 주세요.", {
      meta: "수정 Agent",
      tone: "warn",
    });
    return;
  }
  if (selectedPolicyCompleted()) {
    setMessage("작성 완료 상태에서는 '작성 완료 취소' 후에만 Agent 수정 요청을 할 수 있습니다.", true);
    appendWorkspaceAiChatMessage("assistant", "작성 완료 상태라 바로 다시 실행할 수 없습니다. 작성 완료를 취소한 뒤 다시 눌러 주세요.", {
      meta: "수정 Agent",
      tone: "warn",
    });
    return;
  }
  const actionGroup = sourceButton?.closest(".workspace-ai-agent-card-actions, .workspace-ai-chat-message-actions");
  const actionButtons = actionGroup
    ? [...actionGroup.querySelectorAll("button")]
    : sourceButton
    ? [sourceButton]
    : [];
  actionButtons.forEach((button) => {
    button.disabled = true;
  });
  appendWorkspaceAiChatMessage("user", "다시 실행", { meta: workspaceAiChatScopeLabel() });
  const instructionForAgent = buildWorkspaceAiChatRevisionExecutionInstruction(restartInstruction);
  const started = await startRevisionRequest(instructionForAgent, null, sourceButton, {
    source: "workspace_chat_restart",
    presentation: "chat",
    workspaceChatInstruction: restartInstruction,
  });
  if (!started) {
    actionButtons.forEach((button) => {
      button.disabled = false;
    });
    appendWorkspaceAiChatMessage("assistant", "수정 Agent를 다시 실행하지 못했습니다. 오류 메시지를 확인한 뒤 다시 눌러 주세요.", {
      meta: "수정 Agent",
      tone: "warn",
    });
  }
}

async function cancelWorkspaceAiChatActiveJob(sourceButton = revisionButton) {
  const jobId = currentWorkspaceAiChatCancelableJobId();
  if (!jobId) {
    setMessage("중단할 수 있는 진행 중 작업을 찾지 못했습니다.", true);
    return;
  }
  if (!guardWritePermission("조회 권한은 진행 중 작업 중단을 실행할 수 없습니다.")) return;
  workspaceAiChatCancelingJobIds.add(jobId);
  workspaceAiChatActiveJobStatus = "canceling";
  renderWorkspaceAiChat();
  setMessage("수정 Agent 작업 중단을 요청했습니다.");
  appendWorkspaceAiChatMessage("assistant", "수정 Agent 작업 중단 요청을 보냈습니다. 진행 중인 LLM 결과는 돌아오더라도 문서에 반영하지 않고 작업을 정리합니다.", {
    meta: "수정 Agent",
    tone: "warn",
  });
  try {
    const response = await fetch(apiPath(`/api/jobs/${encodeURIComponent(jobId)}/cancel`), {
      method: "POST",
      headers: jsonHeaders(),
      body: JSON.stringify(withClientSession({ reason: "workspace_chat_stop_button" })),
    });
    const data = await parseJsonResponseOrThrow(response, "대화형 수정 작업 중단");
    if (!response.ok || !data.ok) {
      throw new Error(data.error || "수정 작업 중단 요청에 실패했습니다.");
    }
    if (data.job) {
      updateWorkspaceAiChatActiveJob(data.job);
      if (workspaceAiChatJobIsActive(data.job.status)) {
        startWorkspaceAiChatJobTracking(data.job);
      } else {
        appendWorkspaceAiChatJobStatus(data.job, { force: true });
        closeWorkspaceAiChatJobTracking(jobId);
      }
    } else {
      pollWorkspaceAiChatJob(jobId);
    }
    setMessage("수정 Agent 작업 중단을 요청했습니다. 상태가 정리될 때까지 잠시만 기다려 주세요.");
  } catch (error) {
    workspaceAiChatCancelingJobIds.delete(jobId);
    workspaceAiChatActiveJobStatus = "running";
    renderWorkspaceAiChat();
    appendWorkspaceAiChatMessage("assistant", error.message || "수정 작업 중단 요청 중 오류가 발생했습니다.", {
      meta: "수정 Agent",
      tone: "warn",
    });
    setMessage(error.message || "수정 작업 중단 요청 중 오류가 발생했습니다.", true);
    if (sourceButton) sourceButton.disabled = false;
  }
}

async function applyWorkspaceAiChatRevisionMessage(messageId, sourceButton = null) {
  if (isWorkspaceAiChatWorking()) return;
  const message = workspaceAiChatMessages.find((item) => item?.id === messageId);
  const revisionInstruction = workspaceAiChatRevisionInstruction(message);
  if (!message || !revisionInstruction) {
    appendWorkspaceAiChatMessage("assistant", "반영할 수정안을 찾지 못했습니다. 다시 수정/보완 방향을 얘기해 주세요.", {
      meta: "공동작업",
      tone: "warn",
    });
    return;
  }
  if (!canCurrentUserWritePolicies()) {
    setMessage("조회 권한이라 문서 반영 작업은 실행하지 않았습니다.", true);
    appendWorkspaceAiChatMessage("assistant", "현재 계정은 조회 권한이라 문서 반영을 실행할 수 없습니다. 편집 권한으로 전환한 뒤 다시 눌러 주세요.", {
      meta: "공동작업",
      tone: "warn",
    });
    return;
  }
  if (selectedPolicyCompleted()) {
    setMessage("작성 완료 상태에서는 '작성 완료 취소' 후에만 Agent 수정 요청을 할 수 있습니다.", true);
    appendWorkspaceAiChatMessage("assistant", "작성 완료 상태라 바로 반영할 수 없습니다. 작성 완료를 취소한 뒤 다시 눌러 주세요.", {
      meta: "공동작업",
      tone: "warn",
    });
    return;
  }

  message.applyPending = true;
  message.appliedAt = new Date().toISOString();
  saveWorkspaceAiChatMessages({ persist: false });
  renderWorkspaceAiChat();
  appendWorkspaceAiChatMessage("user", "반영해줘", { meta: workspaceAiChatScopeLabel() });

  const instructionForAgent = buildWorkspaceAiChatRevisionExecutionInstruction(revisionInstruction);

  if (selectedDraft) {
    const resumed = await requestDraftRevision(instructionForAgent);
    appendWorkspaceAiChatMessage(
      "assistant",
      resumed
        ? "수정안을 반영해 중단된 초안 작성을 이어서 시작했습니다. 진행 상태는 이 대화창에 남기겠습니다."
        : "초안 이어쓰기를 시작하지 못했습니다. 체크포인트와 권한 상태를 확인해 주세요.",
      { meta: "수정 Agent", tone: resumed ? "good" : "warn" }
    );
    if (!resumed) {
      message.applyPending = false;
      message.appliedAt = "";
      saveWorkspaceAiChatMessages({ persist: false });
      renderWorkspaceAiChat();
    }
    return;
  }

  const started = await startRevisionRequest(instructionForAgent, null, sourceButton, {
    source: "workspace_chat_apply",
    presentation: "chat",
    workspaceChatInstruction: revisionInstruction,
  });
  if (!started) {
    message.applyPending = false;
    message.appliedAt = "";
    saveWorkspaceAiChatMessages({ persist: false });
    renderWorkspaceAiChat();
    appendWorkspaceAiChatMessage("assistant", "수정 Agent 작업을 시작하지 못했습니다. 오류 메시지를 확인한 뒤 다시 눌러 주세요.", {
      meta: "수정 Agent",
      tone: "warn",
    });
  }
}

