          '<section class="domain-map-column"><div class="domain-map-title">도메인</div>' + domains.map(function (group) { return domainNode(group, 'domain', 'domain'); }).join('') + (groupedCounts(resultRows, 'domain', 0).length > domains.length ? '<div class="domain-map-more">외 ' + escapeHtml(formatNumber(groupedCounts(resultRows, 'domain', 0).length - domains.length)) + '개 도메인</div>' : '') + '</section>' +
          '<section class="domain-map-column"><div class="domain-map-title">분과</div>' + divisions.map(function (group) { return domainNode(group, 'division', 'division'); }).join('') + (groupedCounts(resultRows, 'division', 0).length > divisions.length ? '<div class="domain-map-more">외 ' + escapeHtml(formatNumber(groupedCounts(resultRows, 'division', 0).length - divisions.length)) + '개 분과</div>' : '') + '</section>' +
          '</div></div>';
