function jsonForInlineScript(value) {
  return JSON.stringify(value)
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");
}

function parseRequirementMappingStatus(value = "") {
  const text = String(value || "").trim();
  if (!text || text === "-") {
    return { raw: text, status: "", policyTopic: "", items: [], itemCount: 0 };
  }
  const parts = text.split("·").map((part) => part.trim()).filter(Boolean);
  const status = parts[0] || text;
  const policyTopic = (parts[1] || "").replace(/\s*정책서\s*$/u, "").trim();
  const itemText = parts.slice(2).join(" · ");
  const itemParts = itemText
    .split(/\s+\/\s+/u)
    .map((part) => part.trim())
    .filter(Boolean);
  const items = itemParts.map((item) => {
    const cleaned = item.replace(/\s+외\s+\d+건\s*$/u, "").trim();
    const idMatch = cleaned.match(/(?:FINAL_CHECK:\d+|[A-Z]{2,}-[A-Z0-9][A-Z0-9-]*(?::\d+)?)/u);
    const id = idMatch?.[0] || "";
    const type = id ? cleaned.slice(0, cleaned.indexOf(id)).trim() : "";
    const name = id ? cleaned.slice(cleaned.indexOf(id) + id.length).trim() : cleaned;
    return { raw: cleaned, type, id, name };
  });
  const extraMatch = text.match(/외\s+(\d+)건/u);
  const extraCount = extraMatch ? Number(extraMatch[1] || 0) : 0;
  return {
    raw: text,
    status,
    policyTopic,
    items,
    itemCount: items.length + extraCount,
  };
}

function requirementMappingStatusClass(status = "") {
  const normalized = String(status || "");
  if (normalized.includes("반영 완료")) return "done";
  if (normalized.includes("검토")) return "review";
  if (normalized.includes("후속")) return "later";
  if (normalized.includes("미반영") || normalized.includes("제외")) return "blocked";
  return "empty";
}

function renderRequirementMappingCell(row = {}, index = 0) {
  const mapping = parseRequirementMappingStatus(row.policy_mapping_status || "");
  if (!mapping.status) return `<span class="mapping-empty">-</span>`;
  const statusClass = requirementMappingStatusClass(mapping.status);
  const summary = mapping.policyTopic
    ? `${mapping.policyTopic} 정책서${mapping.itemCount ? ` · ${mapping.itemCount}개 항목` : ""}`
    : mapping.raw;
  return `
    <button class="mapping-summary-button ${statusClass}" type="button" data-mapping-index="${Number(index)}">
      <span class="mapping-status-chip">${escapeHtml(mapping.status)}</span>
      <span class="mapping-summary-text">${escapeHtml(summary)}</span>
    </button>
  `;
}

