function renderPolicyGraphActivityItemExpansion(node) {
  if (!node || !latestPolicyGraphPayload) return;
  if (!latestPolicyGraphStructureData) {
    latestPolicyGraphStructureData = buildPolicyGraphStructureData(latestPolicyGraphPayload);
  }
  const baseNodes = Array.isArray(latestPolicyGraphStageExpansionNodes) && latestPolicyGraphStageExpansionNodes.some((item) => item.id === node.id)
    ? latestPolicyGraphStageExpansionNodes
    : [...(latestPolicyGraphStructureData?.nodes || []), node];
  const baseEdges = (latestPolicyGraphStructureData?.edges || []).slice();
  const steps = policyGraphActivityItemImpactSteps(node);
  const impactNodes = steps.map((step, index) => ({
    id: `${node.id}:impact:${step.id}`,
    type: step.type,
    title: step.title,
    visualRole: "impactItem",
    stageChildIndex: index,
    targetStageId: step.targetStageId,
    sourceId: node.sourceId || "",
    sourcePath: node.sourcePath || "",
    summary: step.summary,
    traceStatus: "활용 경로",
  }));
  const itemEdges = [
    ...impactNodes.map((impact) => ({
      source: node.id,
      target: impact.id,
      type: "DERIVED_FROM",
      label: "활용",
      expansionScope: "activityImpact",
    })),
    ...impactNodes.map((impact, index) => ({
      source: impact.id,
      target: steps[index].targetStageId,
      type: steps[index].id === "policy" ? "COVERS" : "MAPS_TO",
      label: steps[index].label,
      expansionScope: "activityImpact",
    })),
  ];
  activePolicyGraphTab = "explore";
  latestPolicyGraphExpansion = {
    stageExpansionType: "activity-item",
    anchorNodeId: node.id,
    rootId: node.id,
    depth: 1,
  };
  latestPolicyGraphStageExpansionNodes = [...baseNodes.filter((item) => !String(item.id || "").includes(":impact:")), ...impactNodes];
  latestPolicyGraphStageExpansionEdges = [...baseEdges, ...itemEdges];
  policyGraphRootNodeId = node.id;
  selectedPolicyGraphNodeId = node.id;
  policyGraphDepth = 1;
  if (policyGraphDepthRange) policyGraphDepthRange.value = "1";
  if (policyGraphDepthValue) policyGraphDepthValue.textContent = "1";
  if (policyGraphDepthMoreButton) policyGraphDepthMoreButton.disabled = true;
  if (policyGraphExploreControls) policyGraphExploreControls.hidden = false;
  if (policyGraphCanvasTitle) policyGraphCanvasTitle.textContent = "통합 그래프";
  if (policyGraphCanvasDescription) {
    policyGraphCanvasDescription.textContent = `${node.title || "선택한 산출물"}이 뒤 단계에서 어떻게 활용되는지 펼쳤습니다. 이 산출물은 과제 정의, 요구사항, 정책서 작성의 근거로 연결됩니다.`;
  }
  renderPolicyGraphCanvas(latestPolicyGraphStageExpansionNodes, latestPolicyGraphStageExpansionEdges, {
    mode: "combined",
    rootId: node.id,
    anchorNodeId: node.id,
  });
  selectPolicyGraphNode(node.id);
}

